import { Link } from "react-router-dom";
import "./ServicesStyles.css";

function ServicesData(props){
    return(
        <div className="s-card">
            <div className="s-image">
                <Link>
                </Link> 
                
            </div>     
        <h4>{props.heading}</h4>
        <p>{props.text}</p>
        </div>
    );
}

export default ServicesData;
